<template>
  <div>
    <div class="card card-body p-4 m-3" v-if="displayQuestion">
        <QuestionWrapper :userID="userID" :question="question" :messages="messages" @loadNewQuestion="goToLibrary()"/>
    </div>
  </div>
</template>

<script>

import QuestionWrapper from './QuestionWrapper.vue'
import ServerTalker from '../ServerTalker'
export default {
    name: 'Question',
    props: {
        userID: String,
        prop: String, //question id
    },
    components: {
        QuestionWrapper
    },
    data() {
        return {
            questionID: '',
            question: undefined,
            displayQuestion: false,
            messages: {
                submittionReply: '',
            },

        }
    },
    async created() {
        this.questionID = this.prop
        try {
            this.question = await ServerTalker.loadQuestion(this.questionID, this.userID, await this.$auth.getTokenSilently())
            this.displayQuestion = true
            
      } catch(err) {
        this.messages.loadQuestion = "Error: " + err.message
      }
    },
    methods: {
        goToLibrary() {
            window.location.href = '/library'
        },
    },
    
}
</script>

<style>
    .transition {
        transition: all 300ms ease-in-out;
    }
    .condensable {
        --question-height: fit-content;
        overflow: hidden;
        max-height: var(--question-height);
    }
    .condensable.condensed {
        max-height: 0;
    }

    .transition.blur {
        color: transparent;
        text-shadow: 0 0 16px #000;
        -webkit-touch-callout: none;
        -webkit-user-select: none;
        -khtml-user-select: none;
        -moz-user-select: none;
        -ms-user-select: none;
        user-select: none;
    }
</style>